import java.io.*;class Main{static int solve(int n){if(n==0)return 0;StringBuilder sb=new StringBuilder();while(n>0){sb.append((char)('0'+n%9));n/=9;}return Integer.parseInt(sb.reverse().toString());}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int t=Integer.parseInt(d[0]);StringBuilder out=new StringBuilder();for(int i=0;i<t;i++){if(i>0)out.append("\n\n");out.append(solve(Integer.parseInt(d[i+1])));}System.out.print(out);}}
